import{_ as n}from"./chunks/plugin-vue_export-helper.DlAUqK2U.js";import{C as i,c as s,o as t,ab as a,b as l,w as o,a as c,G as g,ac as d}from"./chunks/mermaid.y64gfTUe.js";import"./chunks/cytoscape.C2CwDKBM.js";import"./chunks/dayjs.C32PoDnw.js";const I=JSON.parse('{"title":"Path 2: Add AI Features - Integrate AI into Apps","description":"","frontmatter":{},"headers":[],"relativePath":"paths/integration.md","filePath":"paths/integration.md"}'),u={name:"paths/integration.md"};function h(p,e,m,f,A,y){const r=i("Mermaid");return t(),s("div",null,[e[1]||(e[1]=a('<h1 id="path-2-add-ai-features-integrate-ai-into-apps" tabindex="-1">Path 2: Add AI Features - Integrate AI into Apps <a class="header-anchor" href="#path-2-add-ai-features-integrate-ai-into-apps" aria-label="Permalink to &quot;Path 2: Add AI Features - Integrate AI into Apps&quot;">​</a></h1><p><strong>Time Investment</strong>: 2-4 weeks (30 minutes/day) <strong>Difficulty</strong>: Intermediate <strong>Prerequisites</strong>: React/Next.js basics, Node.js knowledge, API Key (OpenAI/Anthropic)</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>This learning path transforms you from a frontend consumer of AI tools into a <strong>builder of AI-powered applications</strong>. You will learn to integrate LLMs directly into your user interfaces, handle streaming responses, manage AI state, and build production-ready features like chatbots and semantic search.</p><p><strong>What You&#39;ll Build</strong>:</p><ul><li>💬 <strong>Streaming Chatbots</strong> that feel like ChatGPT</li><li>📝 <strong>AI Form Autocomplete</strong> to speed up data entry</li><li>🔍 <strong>Semantic Search</strong> to find meaning, not just keywords</li><li>🛠️ <strong>Tool-Using Agents</strong> that can fetch data and perform actions</li><li>🛡️ <strong>Robust Error Handling</strong> for unreliable AI responses</li></ul><h2 id="learning-path-overview" tabindex="-1">Learning Path Overview <a class="header-anchor" href="#learning-path-overview" aria-label="Permalink to &quot;Learning Path Overview&quot;">​</a></h2>',7)),(t(),l(d,null,{default:o(()=>[g(r,{id:"mermaid-45",class:"mermaid",graph:"graph%20LR%0A%20%20%20%20A%5BWeek%201%3A%20Foundations%5D%20--%3E%20B%5BWeek%202%3A%20Advanced%20Integration%5D%0A%20%20%20%20B%20--%3E%20C%5BWeek%203%3A%20Production%20Projects%5D%0A%20%20%20%20%0A%20%20%20%20A%20--%3E%20A1%5BDays%201-3%3A%20API%20Basics%5D%0A%20%20%20%20A%20--%3E%20A2%5BDays%204-7%3A%20Streaming%20UI%5D%0A%20%20%20%20%0A%20%20%20%20B%20--%3E%20B1%5BDays%208-10%3A%20RAG%20Patterns%5D%0A%20%20%20%20B%20--%3E%20B2%5BDays%2011-14%3A%20Tool%20Use%5D%0A%20%20%20%20%0A%20%20%20%20C%20--%3E%20C1%5BDays%2015-21%3A%20Full%20Features%5D%0A%0A%20%20%20%20style%20A%20fill%3A%23e1f5ff%0A%20%20%20%20style%20B%20fill%3A%23d4edda%0A%20%20%20%20style%20C%20fill%3A%23fff3cd%0A"})]),fallback:o(()=>[...e[0]||(e[0]=[c(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=a('<h2 id="week-1-foundations-days-1-7" tabindex="-1">Week 1: Foundations (Days 1-7) <a class="header-anchor" href="#week-1-foundations-days-1-7" aria-label="Permalink to &quot;Week 1: Foundations (Days 1-7)&quot;">​</a></h2><h3 id="days-1-3-api-fundamentals" tabindex="-1">Days 1-3: API Fundamentals <a class="header-anchor" href="#days-1-3-api-fundamentals" aria-label="Permalink to &quot;Days 1-3: API Fundamentals&quot;">​</a></h3><p>Understand how to communicate with Large Language Models (LLMs) via API.</p><h4 id="core-concepts" tabindex="-1">Core Concepts <a class="header-anchor" href="#core-concepts" aria-label="Permalink to &quot;Core Concepts&quot;">​</a></h4><ol><li><strong>Request/Response Model</strong>: Text-in, text-out.</li><li><strong>Authentication</strong>: API keys and environment variables.</li><li><strong>Models</strong>: Differences between GPT-4o, Claude 3.5 Sonnet, Gemini 1.5.</li><li><strong>Cost</strong>: Tokens, input vs. output pricing.</li></ol><p><strong>Key Resources</strong>:</p><ul><li><a href="./../integration/apis/">API Comparison</a></li><li><a href="./../integration/apis/openai.html">OpenAI Integration Guide</a></li><li><a href="./../integration/apis/anthropic.html">Anthropic Integration Guide</a></li></ul><p><strong>Daily Practice (30 min/day)</strong>:</p><ol><li><strong>Day 1</strong>: Sign up for OpenAI/Anthropic, get API key, make first curl request.</li><li><strong>Day 2</strong>: Create a simple Node.js script to send a prompt and log response.</li><li><strong>Day 3</strong>: Experiment with system prompts vs. user prompts to change behavior.</li></ol><p><strong>Success Milestone</strong>: Successfully receive a structured JSON response from an LLM.</p><hr><h3 id="days-4-7-streaming-user-interfaces" tabindex="-1">Days 4-7: Streaming User Interfaces <a class="header-anchor" href="#days-4-7-streaming-user-interfaces" aria-label="Permalink to &quot;Days 4-7: Streaming User Interfaces&quot;">​</a></h3><p>Users expect AI to &quot;type&quot; out answers. Learn to implement streaming.</p><h4 id="the-streaming-challenge" tabindex="-1">The Streaming Challenge <a class="header-anchor" href="#the-streaming-challenge" aria-label="Permalink to &quot;The Streaming Challenge&quot;">​</a></h4><ul><li><strong>Standard API</strong>: Waits for full generation (slow!).</li><li><strong>Streaming API</strong>: Sends chunks of text as they are generated (fast TTFT - Time To First Token).</li><li><strong>Frontend</strong>: Needs to update state incrementally without flickering.</li></ul><p><strong>Tools</strong>:</p><ul><li><strong>Vercel AI SDK</strong>: The standard for React/Next.js AI apps.</li><li><strong>Server Sent Events (SSE)</strong>: The protocol behind the scenes.</li></ul><p><strong>Key Resources</strong>:</p><ul><li><a href="./../tech/frontend/streaming.html">Streaming Fundamentals</a></li><li><a href="./../integration/frameworks/vercel-ai-sdk.html">Vercel AI SDK Guide</a></li><li><a href="./../cookbook/chat-ui.html">Cookbook: Chat UI</a></li></ul><p><strong>Daily Practice</strong>:</p><ol><li><strong>Day 4</strong>: Set up a Next.js project with Vercel AI SDK.</li><li><strong>Day 5</strong>: Implement <code>useChat</code> hook for a basic chatbot.</li><li><strong>Day 6</strong>: Build a <code>useCompletion</code> component for text generation.</li><li><strong>Day 7</strong>: Customize the UI (loading states, error handling).</li></ol><p><strong>Success Milestone</strong>: A functional chat interface that streams responses token-by-token.</p><hr><h2 id="week-2-advanced-integration-days-8-14" tabindex="-1">Week 2: Advanced Integration (Days 8-14) <a class="header-anchor" href="#week-2-advanced-integration-days-8-14" aria-label="Permalink to &quot;Week 2: Advanced Integration (Days 8-14)&quot;">​</a></h2><h3 id="days-8-10-rag-retrieval-augmented-generation" tabindex="-1">Days 8-10: RAG (Retrieval Augmented Generation) <a class="header-anchor" href="#days-8-10-rag-retrieval-augmented-generation" aria-label="Permalink to &quot;Days 8-10: RAG (Retrieval Augmented Generation)&quot;">​</a></h3><p>Teach AI about <em>your</em> data.</p><h4 id="concept-rag" tabindex="-1">Concept: RAG <a class="header-anchor" href="#concept-rag" aria-label="Permalink to &quot;Concept: RAG&quot;">​</a></h4><ol><li><strong>Retrieve</strong>: Find relevant data (docs, database rows) based on user query.</li><li><strong>Augment</strong>: Paste that data into the prompt context.</li><li><strong>Generate</strong>: Ask LLM to answer using only that data.</li></ol><p><strong>Key Resources</strong>:</p><ul><li><a href="./../tech/patterns/RAG.html">RAG Pattern Explained</a></li><li><a href="./../tech/fundamentals/embeddings.html">Embeddings Guide</a></li><li><a href="./../integration/frameworks/llamaindex-ts.html">LlamaIndex TS Guide</a></li></ul><p><strong>Daily Practice</strong>:</p><ol><li><strong>Day 8</strong>: Generate embeddings for a list of text strings.</li><li><strong>Day 9</strong>: Implement a simple cosine similarity search function.</li><li><strong>Day 10</strong>: Build a &quot;Chat with your Text File&quot; feature.</li></ol><p><strong>Success Milestone</strong>: Ask a question about a specific private document and get a correct answer.</p><hr><h3 id="days-11-14-tool-calling-agents" tabindex="-1">Days 11-14: Tool Calling (Agents) <a class="header-anchor" href="#days-11-14-tool-calling-agents" aria-label="Permalink to &quot;Days 11-14: Tool Calling (Agents)&quot;">​</a></h3><p>Turn AI from a chatbot into an agent that <em>does</em> things.</p><h4 id="concept-function-calling" tabindex="-1">Concept: Function Calling <a class="header-anchor" href="#concept-function-calling" aria-label="Permalink to &quot;Concept: Function Calling&quot;">​</a></h4><ul><li>Describe functions (tools) to the LLM (e.g., <code>getWeather(city)</code>).</li><li>LLM returns a JSON request to call that function.</li><li>You execute the function code and return the result to the LLM.</li><li>LLM generates a natural language response based on the result.</li></ul><p><strong>Key Resources</strong>:</p><ul><li><a href="./../integration/protocols/tool-calling.html">Tool Calling Guide</a></li><li><a href="./../integration/protocols/mcp.html">MCP Protocol</a></li><li><a href="./../tech/frontend/generative-ui.html">Generative UI</a></li></ul><p><strong>Daily Practice</strong>:</p><ol><li><strong>Day 11</strong>: Define a simple tool (e.g., calculator or weather mocker).</li><li><strong>Day 12</strong>: Implement the loop: Prompt -&gt; LLM decides tool -&gt; Execute tool -&gt; LLM explains result.</li><li><strong>Day 13</strong>: Use Vercel AI SDK&#39;s <code>tool</code> support for easier integration.</li><li><strong>Day 14</strong>: <strong>Advanced</strong>: Render a UI component based on the tool result (Generative UI).</li></ol><p><strong>Success Milestone</strong>: An app where asking &quot;What&#39;s the weather?&quot; triggers code execution and shows data.</p><hr><h2 id="week-3-production-projects-days-15-21" tabindex="-1">Week 3: Production Projects (Days 15-21) <a class="header-anchor" href="#week-3-production-projects-days-15-21" aria-label="Permalink to &quot;Week 3: Production Projects (Days 15-21)&quot;">​</a></h2><p>Combine everything into polished features.</p><h3 id="project-1-smart-form-autocomplete" tabindex="-1">Project 1: Smart Form Autocomplete <a class="header-anchor" href="#project-1-smart-form-autocomplete" aria-label="Permalink to &quot;Project 1: Smart Form Autocomplete&quot;">​</a></h3><p><strong>Goal</strong>: A form that fills itself based on a short user description. <strong>Stack</strong>: Next.js, Vercel AI SDK (<code>useObject</code>). <strong>Features</strong>:</p><ul><li>User types &quot;Flight to Paris next Friday&quot;</li><li>Form auto-fills: Destination: Paris, Date: [Next Friday&#39;s Date]</li><li><strong>Key Skill</strong>: Structured Output (JSON mode).</li></ul><h3 id="project-2-documentation-q-a-bot" tabindex="-1">Project 2: Documentation Q&amp;A Bot <a class="header-anchor" href="#project-2-documentation-q-a-bot" aria-label="Permalink to &quot;Project 2: Documentation Q&amp;A Bot&quot;">​</a></h3><p><strong>Goal</strong>: A chatbot widget for a documentation site. <strong>Stack</strong>: Next.js, OpenAI, Supabase (pgvector) or simple in-memory vector store. <strong>Features</strong>:</p><ul><li>RAG pipeline for documentation.</li><li>Source citations (&quot;Answer found in section X&quot;).</li><li><strong>Key Skill</strong>: RAG and context management.</li></ul><h3 id="project-3-ai-dashboard-analyst" tabindex="-1">Project 3: AI Dashboard Analyst <a class="header-anchor" href="#project-3-ai-dashboard-analyst" aria-label="Permalink to &quot;Project 3: AI Dashboard Analyst&quot;">​</a></h3><p><strong>Goal</strong>: An admin panel that answers questions about data. <strong>Stack</strong>: Next.js, Recharts, Tool Calling. <strong>Features</strong>:</p><ul><li>&quot;Show me sales for last week&quot; -&gt; Renders a chart.</li><li>&quot;List top users&quot; -&gt; Renders a table.</li><li><strong>Key Skill</strong>: Generative UI / Dynamic Component Rendering.</li></ul><hr><h2 id="api-integration-checklist" tabindex="-1">API Integration Checklist <a class="header-anchor" href="#api-integration-checklist" aria-label="Permalink to &quot;API Integration Checklist&quot;">​</a></h2><p>Before shipping, ensure you handle these production concerns:</p><h3 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h3><ul><li>[ ] <strong>API Keys</strong>: Never exposed on client-side. Use API routes/proxies.</li><li>[ ] <strong>Rate Limiting</strong>: Prevent one user from draining your credits.</li><li>[ ] <strong>Content Moderation</strong>: Filter inappropriate inputs/outputs.</li></ul><h3 id="user-experience" tabindex="-1">User Experience <a class="header-anchor" href="#user-experience" aria-label="Permalink to &quot;User Experience&quot;">​</a></h3><ul><li>[ ] <strong>Optimistic UI</strong>: Show user input immediately.</li><li>[ ] <strong>Loading States</strong>: Skeletons or spinners during &quot;Thinking...&quot; phase.</li><li>[ ] <strong>Stream Handling</strong>: Smooth text rendering (no jitter).</li><li>[ ] <strong>Feedback</strong>: Allow users to rate responses (thumbs up/down).</li></ul><h3 id="reliability" tabindex="-1">Reliability <a class="header-anchor" href="#reliability" aria-label="Permalink to &quot;Reliability&quot;">​</a></h3><ul><li>[ ] <strong>Fallbacks</strong>: Handle API downtime gracefully.</li><li>[ ] <strong>Retries</strong>: Exponential backoff for failed requests.</li><li>[ ] <strong>Timeouts</strong>: Don&#39;t let requests hang forever.</li></ul><hr><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><h3 id="path-3-mastery-4-weeks" tabindex="-1">Path 3: Mastery (4+ weeks) <a class="header-anchor" href="#path-3-mastery-4-weeks" aria-label="Permalink to &quot;Path 3: Mastery (4+ weeks)&quot;">​</a></h3><p>Move from integration to <strong>building complete AI products and platforms</strong>:</p><ul><li>🏗️ <strong>Advanced RAG</strong>: Hybrid search, re-ranking, knowledge graphs.</li><li>🧪 <strong>Evals &amp; Testing</strong>: Systematically improving prompt quality.</li><li>🚀 <strong>Ops</strong>: Monitoring, finetuning, and cost optimization.</li><li>🤖 <strong>Multi-Agent Systems</strong>: Complex autonomous workflows.</li></ul><p><strong>Coming Soon</strong>: <a href="./mastery.html">Path 3: Mastery</a></p><hr><h2 id="additional-resources" tabindex="-1">Additional Resources <a class="header-anchor" href="#additional-resources" aria-label="Permalink to &quot;Additional Resources&quot;">​</a></h2><h3 id="documentation" tabindex="-1">Documentation <a class="header-anchor" href="#documentation" aria-label="Permalink to &quot;Documentation&quot;">​</a></h3><ul><li><a href="https://sdk.vercel.ai/docs" target="_blank" rel="noreferrer">Vercel AI SDK Documentation</a></li><li><a href="https://platform.openai.com/docs/api-reference" target="_blank" rel="noreferrer">OpenAI API Reference</a></li><li><a href="https://docs.anthropic.com/en/api/getting-started" target="_blank" rel="noreferrer">Anthropic API Reference</a></li></ul><h3 id="community-examples" tabindex="-1">Community Examples <a class="header-anchor" href="#community-examples" aria-label="Permalink to &quot;Community Examples&quot;">​</a></h3><ul><li><a href="https://vercel.com/templates?search=ai" target="_blank" rel="noreferrer">Vercel AI Templates</a></li><li><a href="https://github.com/langchain-ai/langchainjs" target="_blank" rel="noreferrer">LangChain.js Examples</a></li></ul><hr><p><strong>Ready to start?</strong> Begin by getting your API keys and setting up the basic environment!</p><p><strong>Time to complete</strong>: 2-4 weeks <strong>Expected Outcome</strong>: 3 Portfolio-ready AI features <strong>Next learning path</strong>: <a href="./mastery.html">Path 3: Mastery</a> 🚧</p>',79))])}const x=n(u,[["render",h]]);export{I as __pageData,x as default};
